#include <bits/stdc++.h>
using namespace std;
long long f[10001];
long long P=1e9 + 7;
int main(){
    int n,w;
    cin>>n>>w;
    long long a[n];
    for(int i=0;i<n;i++){
        cin>>a[i];
    }
    f[0]=1;
    for(int i=1;i<=w;i++){
        for(int j=0;j<n;j++){
            if(i>=a[j]){
                f[i]=(f[i]+f[i-a[j]])%P;
            }
        }
    }
    cout<<f[w];
    return 0;
}
